import React, { useEffect, useState } from "react";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Myappointments() {
  const [appointments, setAppointments] = useState([]);

  // ✅ FETCH APPOINTMENTS
  useEffect(() => {
    fetch("http://127.0.0.1:8000/my-appointments/", {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        console.log("Appointments:", data);
        setAppointments(data);
      })
      .catch((err) => console.error(err));
  }, []);

  // ✅ CANCEL APPOINTMENT
  const handleCancel = async (id) => {
    if (!window.confirm("Cancel this appointment?")) return;

    try {
      const res = await fetch(
        `http://127.0.0.1:8000/cancel-appointment/${id}/`,
        {
          method: "DELETE",
          headers: {
            Authorization: `Token ${localStorage.getItem("token")}`,
          },
        }
      );

      if (res.ok) {
        alert("Cancelled successfully");

        // remove from UI
        setAppointments((prev) => prev.filter((a) => a.id !== id));
      } else {
        alert("Cancel failed");
      }
    } catch (error) {
      console.error(error);
    }
  };

  // ✅ SPLIT UPCOMING & PAST
  const today = new Date().toISOString().split("T")[0];

  const upcoming = appointments.filter(
    (a) => a.appointment_date >= today
  );

  const past = appointments.filter(
    (a) => a.appointment_date < today
  );

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>

        {/* UPCOMING */}
        <div style={styles.headingContainer}>
          <h2 style={styles.heading}>📅 Upcoming Appointments</h2>
          <div style={styles.underline}></div>
        </div>

        <div style={styles.grid}>
          {upcoming.length > 0 ? (
            upcoming.map((a) => (
              <div key={a.id} style={styles.card}>
                <h3>{a.doctor_name}</h3>
                <p>
                  📅 {a.appointment_date} | ⏰ {a.time_slot}
                </p>

                <span style={{ ...styles.status, ...styles.confirmed }}>
                  Confirmed
                </span>

                <button
                  style={styles.cancelButton}
                  onClick={() => handleCancel(a.id)}
                >
                  Cancel
                </button>
              </div>
            ))
          ) : (
            <p>No upcoming appointments</p>
          )}
        </div>

        {/* PAST */}
        <div style={styles.headingContainer}>
          <h2 style={styles.heading}>🕘 Past Appointments</h2>
          <div style={styles.underline}></div>
        </div>

        <div style={styles.grid}>
          {past.length > 0 ? (
            past.map((a) => (
              <div key={a.id} style={styles.card}>
                <h3>{a.doctor_name}</h3>
                <p>📅 {a.appointment_date}</p>

                <span style={{ ...styles.status, ...styles.completed }}>
                  Completed
                </span>
              </div>
            ))
          ) : (
            <p>No past appointments</p>
          )}
        </div>

      </div>

      <Footer />
    </div>
  );
}

export default Myappointments;

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
    fontFamily: "Arial, sans-serif",
  },

  main: {
    flex: 1,
    padding: "40px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
  },

  headingContainer: {
    width: "900px",
    marginBottom: "20px",
  },

  heading: {
    fontSize: "22px",
    fontWeight: "600",
    color: "#2c3e50",
    marginBottom: "5px",
  },

  underline: {
    width: "50px",
    height: "3px",
    backgroundColor: "#3498db",
    borderRadius: "5px",
  },

  grid: {
    display: "flex",
    flexWrap: "wrap",
    gap: "20px",
    justifyContent: "center",
    marginBottom: "40px",
    maxWidth: "900px",
    width: "100%",
  },

  card: {
    backgroundColor: "#fff",
    padding: "20px",
    borderRadius: "12px",
    width: "280px",
    boxShadow: "0 6px 15px rgba(0,0,0,0.08)",
    transition: "0.3s",
  },

  status: {
    display: "inline-block",
    marginTop: "10px",
    padding: "5px 12px",
    borderRadius: "20px",
    fontSize: "12px",
    fontWeight: "bold",
  },

  confirmed: {
    backgroundColor: "#eafaf1",
    color: "#27ae60",
  },

  pending: {
    backgroundColor: "#fef5e7",
    color: "#f39c12",
  },

  completed: {
    backgroundColor: "#e8f8f5",
    color: "#16a085",
  },

  cancelled: {
    backgroundColor: "#fdecea",
    color: "#e74c3c",
  },

  cancelButton: {
    marginTop: "15px",
    width: "100%",
    padding: "8px",
    backgroundColor: "#e74c3c",
    color: "#fff",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
  },
};
